function solve(grid) {
    const m = grid.length;
    if (m === 0) return 0;
    const n = grid[0].length;
    if (n === 0) return 0;

    // DP[i][j] stores a Set of all possible XOR sums achievable to reach (i, j)
    // Initialize DP table of size m x n, where each element is a Set
    const dp = Array(m).fill(0).map(() => Array(n).fill(0).map(() => new Set()));

    // Base case: starting cell (0, 0)
    dp[0][0].add(grid[0][0]);

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const currentValue = grid[i][j];

            if (i === 0 && j === 0) {
                continue;
            }

            let currentXORs = new Set();

            // Coming from top (i-1, j)
            if (i > 0) {
                for (const prevXOR of dp[i - 1][j]) {
                    currentXORs.add(prevXOR ^ currentValue);
                }
            }

            // Coming from left (i, j-1)
            if (j > 0) {
                for (const prevXOR of dp[i][j - 1]) {
                    currentXORs.add(prevXOR ^ currentValue);
                }
            }

            dp[i][j] = currentXORs;
        }
    }

    const finalXORs = dp[m - 1][n - 1];

    if (finalXORs.size === 0) {
        // Should not happen given constraints m*n >= 1
        return 0; 
    }

    let minXOR = Infinity;
    for (const xorSum of finalXORs) {
        if (xorSum < minXOR) {
            minXOR = xorSum;
        }
    }

    return minXOR;
}

