import java.util.HashSet;
import java.util.Set;

public class Solution {
    public static long solve(long[][] grid) {
        int m = grid.length;
        if (m == 0) return 0;
        int n = grid[0].length;
        if (n == 0) return 0;

        // dp[i][j] stores the set of all possible XOR sums to reach (i, j)
        // Since Java does not allow direct creation of generic arrays, we suppress the warning.
        @SuppressWarnings("unchecked")
        Set<Long>[][] dp = new HashSet[m][n];

        // Initialize DP table
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                dp[i][j] = new HashSet<>();
            }
        }

        // Base case: starting cell (0, 0)
        dp[0][0].add(grid[0][0]);

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (i == 0 && j == 0) {
                    continue;
                }

                long currentValue = grid[i][j];

                // Coming from top (i-1, j)
                if (i > 0) {
                    for (long prevXOR : dp[i - 1][j]) {
                        dp[i][j].add(prevXOR ^ currentValue);
                    }
                }

                // Coming from left (i, j-1)
                if (j > 0) {
                    for (long prevXOR : dp[i][j - 1]) {
                        dp[i][j].add(prevXOR ^ currentValue);
                    }
                }
            }
        }

        Set<Long> finalXORs = dp[m - 1][n - 1];

        if (finalXORs.isEmpty()) {
            // Should not happen given constraints m*n >= 1
            return 0; 
        }

        long minXOR = Long.MAX_VALUE;
        for (long xorSum : finalXORs) {
            if (xorSum < minXOR) {
                minXOR = xorSum;
            }
        }

        return minXOR;
    }
}

