import java.util.HashSet;
import java.util.Set;

public static long solve(long[][] grid) {
    int m = grid.length;
    if (m == 0) return 0;
    int n = grid[0].length;
    if (n == 0) return 0;

    // DP[i][j] stores a Set of all possible XOR sums achievable to reach (i, j)
    Set<Long>[][] dp = new Set[m][n];

    // Initialization
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            dp[i][j] = new HashSet<>();
        }
    }

    // Base case: starting cell (0, 0)
    dp[0][0].add(grid[0][0]);

    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (i == 0 && j == 0) {
                continue;
            }

            long currentValue = grid[i][j];
            Set<Long> currentXORs = new HashSet<>();

            // Coming from top (i-1, j)
            if (i > 0) {
                for (long prevXOR : dp[i - 1][j]) {
                    currentXORs.add(prevXOR ^ currentValue);
                }
            }

            // Coming from left (i, j-1)
            if (j > 0) {
                for (long prevXOR : dp[i][j - 1]) {
                    currentXORs.add(prevXOR ^ currentValue);
                }
            }

            dp[i][j] = currentXORs;
        }
    }

    Set<Long> finalXORs = dp[m - 1][n - 1];

    if (finalXORs.isEmpty()) {
        // This should not happen given constraints m*n >= 1
        return 0; 
    }

    long minXOR = Long.MAX_VALUE;
    for (long xorSum : finalXORs) {
        if (xorSum < minXOR) {
            minXOR = xorSum;
        }
    }

    return minXOR;
}

